from pyspark.sql import DataFrame, SparkSession

def find(key: str, group_map: dict) -> str:
    if group_map[key] != key:
        group_map[key] = find(group_map[key], group_map)
    return group_map[key]

def find_connected_components_with_hashmap(df: DataFrame) -> DataFrame:
    group_map = {}

    for row in df.collect():
        key_a = row[0]  # Accessing the first column (key_A)
        key_b = row[1]  # Accessing the second column (key_B)

        if key_a not in group_map:
            group_map[key_a] = key_a
        if key_b not in group_map:
            group_map[key_b] = key_b

        group_a = find(key_a, group_map)
        group_b = find(key_b, group_map)

        if group_a != group_b:
            if group_a < group_b:
                group_map[group_b] = group_a
            else:
                group_map[group_a] = group_b

    final_map = {key: find(key, group_map) for key in group_map.keys()}
    final_df = spark.createDataFrame(final_map.items(), ["Key", "Group"])

    return final_df

